\begin{align*}
(\mathbf{v} + \mathbf{w}) \times (\mathbf{v} + \mathbf{w}) &= \mathbf{a} \times \mathbf{a} \\
&= (\mathbf{v} + \mathbf{w}) \times (\mathbf{v} + \mathbf{w}) \\
&= \mathbf{v} \times \mathbf{v} + \mathbf{v} \times \mathbf{w} + \mathbf{w} \times \mathbf{v} + \mathbf{w} \times \mathbf{w} \\
&= \mathbf{0} + \begin{pmatrix} 5 \\ -2 \\ 4 \end{pmatrix} + \begin{pmatrix} -5 \\ 2 \\ -4 \end{pmatrix} + \mathbf{0} \\
&= \begin{pmatrix} 0 \\ 0 \\ 0 \end{pmatrix}
\end{align*}
